import{_ as e,c as t,o as r,ag as o}from"./chunks/framework.S-Qvb3wi.js";const _=JSON.parse('{"title":"合規與監管要求聲明","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Compliance-and-Regulatory.md","filePath":"zh-TW/Compliance-and-Regulatory.md"}'),n={name:"zh-TW/Compliance-and-Regulatory.md"};function i(l,a,s,d,u,c){return r(),t("div",null,a[0]||(a[0]=[o('<h1 id="合規與監管要求聲明" tabindex="-1">合規與監管要求聲明 <a class="header-anchor" href="#合規與監管要求聲明" aria-label="Permalink to &quot;合規與監管要求聲明&quot;">​</a></h1><h2 id="regulation-s-合規義務恪遵" tabindex="-1">Regulation S 合規義務恪遵 <a class="header-anchor" href="#regulation-s-合規義務恪遵" aria-label="Permalink to &quot;Regulation S 合規義務恪遵&quot;">​</a></h2><p>本DGrid Premium許可證之銷售計畫，嚴格依據美國Regulation S相關規範執行，<strong>嚴禁美國境內人士（U.S. persons）參與本計畫</strong>。銷售官網、所有宣傳素材及用戶操作介面，均會以醒目方式標示此參與限制；潛在參與者務必詳閱本項合規要求，並明確理解：<strong>DGrid Premium許可證於首次發行完成後之十二（12）個月內，不得轉讓、轉售或進行任何形式之二次流通</strong>，違反此規定將視為違反合規義務。</p><h2 id="透明化資訊披露原則" tabindex="-1">透明化資訊披露原則 <a class="header-anchor" href="#透明化資訊披露原則" aria-label="Permalink to &quot;透明化資訊披露原則&quot;">​</a></h2><p>所有與DGrid Premium銷售相關之溝通往來、行銷素材製作、宣傳推廣活動及社群媒體發布內容，均以公開透明為核心原則，同時<strong>嚴格排除對美國境內人士之定向行銷或銷售訊息</strong>。相關資訊發布過程中，將全面規避任何可能涉及美國對象的內容表述，確保符合Regulation S合規標準，有效降低監管風險。與此同時，參與者應自行查證所屬司法管轄區之相關監管規範，獨立承擔合規審查責任，確保自身參與行為完全符合當地法律要求，避免因違反地區性監管規定產生相應風險。</p>',5)]))}const h=e(n,[["render",i]]);export{_ as __pageData,h as default};
